sys_script.script:
(function executeRule(current, previous /*null when async*/ ) {


    try {

        // ================================
        // 1. FETCH QUOTA
        // ================================
        var quotaGR = new GlideRecord('x_ctans_incentnow_quota');

        if (!quotaGR.get(current.quota)) {
            return;
        }

        var quotaStatus = quotaGR.getValue('status');

        // ================================
        // 2. BLOCK NON-ACTIVE QUOTA
        // ================================
        if (quotaStatus != 'active') {

            gs.addErrorMessage(
                "Only ACTIVE quotas can be assigned to users. " +
                "Please activate the quota before assignment."
            );

            current.setAbortAction(true);
            return;
        }

        // ================================
        // 3. CHECK EXISTING QUOTA FOR USER
        // ================================
        var existing = new GlideRecord('x_ctans_incentnow_user_quota_assignment');
        existing.addQuery('user', current.user);
        existing.addQuery('sys_id', '!=', current.sys_id); // avoid self
        existing.query();

        if (existing.next()) {

            var existingQuotaGR = new GlideRecord('x_ctans_incentnow_quota');

            if (existingQuotaGR.get(existing.quota)) {
                if (existingQuotaGR.getValue('status') == 'active') {
                    gs.addErrorMessage(
                        "User already has an active quota assigned: " +
                        existingQuotaGR.getDisplayValue() +
                        ". Only one active quota per user is allowed."
                    );

                    current.setAbortAction(true);
                    return;
                }
            }
        }

    } catch (ex) {

        gs.addErrorMessage("Validation failed: " + ex.message);
        current.setAbortAction(true);
    }

})(current, previous);
